## Idempotency Key Store
```python
import time
from dataclasses import dataclass
from typing import Any

@dataclass
class Record:
    key: str
    response: Any
    expires_at: float

class IdempotencyStore:
    def __init__(self, ttl: float = 3600.0) -> None:
        self.ttl = ttl
        self._records: dict[str, Record] = {}

    def get(self, key: str) -> Any | None:
        self._purge()
        record = self._records.get(key)
        return None if record is None else record.response

    def put(self, key: str, response: Any) -> None:
        self._purge()
        self._records[key] = Record(key=key, response=response, expires_at=time.time() + self.ttl)

    def _purge(self) -> None:
        now = time.time()
        for key in [k for k, v in self._records.items() if v.expires_at <= now]:
            del self._records[key]
```

## Geohash Encoder
```python
BASE32 = "0123456789bcdefghjkmnpqrstuvwxyz"

def encode_geohash(lat: float, lon: float, precision: int = 8) -> str:
    lat_range = [-90.0, 90.0]
    lon_range = [-180.0, 180.0]
    bits = [16, 8, 4, 2, 1]
    bit = 0
    ch = 0
    even = True
    out: list[str] = []
    while len(out) < precision:
        if even:
            mid = (lon_range[0] + lon_range[1]) / 2
            if lon >= mid:
                ch |= bits[bit]
                lon_range[0] = mid
            else:
                lon_range[1] = mid
        else:
            mid = (lat_range[0] + lat_range[1]) / 2
            if lat >= mid:
                ch |= bits[bit]
                lat_range[0] = mid
            else:
                lat_range[1] = mid
        even = not even
        if bit < 4:
            bit += 1
        else:
            out.append(BASE32[ch])
            bit = 0
            ch = 0
    return "".join(out)
```

## Token Bucket Rate Limiter
```python
import time
from dataclasses import dataclass

@dataclass
class TokenBucket:
    capacity: float
    refill_rate: float
    tokens: float = 0.0
    last_refill: float = 0.0

    def _refill(self, now: float) -> None:
        if self.last_refill == 0:
            self.last_refill = now
            self.tokens = self.capacity
            return
        elapsed = now - self.last_refill
        self.tokens = min(self.capacity, self.tokens + elapsed * self.refill_rate)
        self.last_refill = now

    def allow(self, cost: float = 1.0) -> bool:
        now = time.monotonic()
        self._refill(now)
        if self.tokens >= cost:
            self.tokens -= cost
            return True
        return False
